import { Component, OnInit } from '@angular/core';
import { CommonModule } from '@angular/common';
import { ActivatedRoute, Router, RouterModule } from '@angular/router';
import { Invoice } from '../../models/invoice';
import { InvoiceCalcService, InvoiceTotals } from '../../services/invoice-calc.service';
import { InvoiceStoreService } from '../../services/invoice-store.service';
import { ElectronService } from '../../services/electron.service';

type TotalsFinal = {
  baseHT: number;   // HT après remise si remise avant TVA
  fodec: number;    // 1% de baseHT
  horsTVA: number;  // baseHT + fodec
  tva: number;      // 19% de horsTVA
  timbre: number;   // 1.000
  ttc: number;      // horsTVA + tva + timbre
};

@Component({
  selector: 'app-invoice-preview',
  standalone: true,
  imports: [CommonModule, RouterModule],
  templateUrl: './invoice-preview.component.html',
  styleUrls: ['./invoice-preview.component.css']
})
export class InvoicePreviewComponent implements OnInit {
  invoice: Invoice | null = null;

  totals: InvoiceTotals = {
    totalHT: 0,
    totalTVA: 0,
    totalTTC: 0,
    remise: 0,
    totalHTApresRemise: 0,
    totalTVAApresRemise: 0
  };

  totalsFinal: TotalsFinal = {
    baseHT: 0,
    fodec: 0,
    horsTVA: 0,
    tva: 0,
    timbre: 1.0,
    ttc: 0
  };

  totalTtcText = '';
  logoAvailable = true;

  constructor(
    private route: ActivatedRoute,
    private router: Router,
    private store: InvoiceStoreService,
    public calc: InvoiceCalcService,
    public electron: ElectronService
  ) {}

  async ngOnInit(): Promise<void> {
    await this.store.load();

    // ✅ id: query ?id= ... sinon /invoices/:id/preview
    let id =
      this.route.snapshot.queryParamMap.get('id') ??
      this.route.snapshot.paramMap.get('id') ??
      this.route.snapshot.paramMap.get('invoiceId') ??
      '';

    // fallback URL
    const href = window.location.href || '';
    if (!id && href) {
      const m1 = href.match(/\/invoices\/([^\/?#]+)\/preview/i);
      if (m1?.[1]) id = m1[1];

      if (!id) {
        const m2 = href.match(/[?&]id=([^&]+)/i);
        if (m2?.[1]) id = decodeURIComponent(m2[1]);
      }
    }

    if (!id) {
      this.invoice = null;
      return;
    }

    const inv = await this.store.getById(id);
    this.invoice = inv;

    if (!inv) return;

    this.totals = this.calc.totals(inv);

    // ✅ base HT : si tu as totalHTApresRemise sinon totalHT
    const baseHT = Number(this.totals.totalHTApresRemise || this.totals.totalHT || 0);

    const fodec = this.round3(baseHT * 0.01);
    const horsTVA = this.round3(baseHT + fodec);
    const tva = this.round3(horsTVA * 0.19);
    const timbre = 1.0;
    const ttc = this.round3(horsTVA + tva + timbre);

    this.totalsFinal = { baseHT, fodec, horsTVA, tva, timbre, ttc };

    // ✅ texte du TTC en lettres (simple)
    this.totalTtcText = this.formatTtcInWords(ttc);
  }

  back(): void {
    this.router.navigate(['/invoices']);
  }

  edit(): void {
    if (!this.invoice) return;
    this.router.navigate(['/invoices', this.invoice.id, 'edit']);
  }

  print(): void {
    window.print();
  }

  savePdfWeb(): void {
    // Web: l'utilisateur choisit "Enregistrer en PDF"
    window.print();
  }

  async exportPdf(): Promise<void> {
    if (!this.invoice) return;
    if (!this.electron.isElectron) return;

    // Ici on garde ton mécanisme existant (ElectronService)
    try {
      const anyElectron: any = this.electron as any;

      if (typeof anyElectron.exportPdf === 'function') {
        await anyElectron.exportPdf();
        return;
      }

      if (anyElectron.ipcRenderer?.invoke) {
        await anyElectron.ipcRenderer.invoke('export-pdf');
        return;
      }

      alert('Export PDF non configuré dans ElectronService.');
    } catch (e) {
      console.error(e);
      alert('Erreur export PDF. Voir console.');
    }
  }

  private round3(n: number): number {
    return Math.round((n + Number.EPSILON) * 1000) / 1000;
  }

  private formatTtcInWords(ttc: number): string {
    // ⚠️ Version simple (tu peux améliorer après)
    // Exemple: "91 035,000 DT"
    const s = ttc.toLocaleString('fr-FR', { minimumFractionDigits: 3, maximumFractionDigits: 3 });
    return `${s} DT`;
  }
}
<div class="preview-toolbar no-print">
  <button class="btn ghost" (click)="back()">Retour</button>

  <div class="toolbar-actions">
    <button class="btn outline" (click)="edit()" [disabled]="!invoice">Modifier</button>

    <button class="btn primary" (click)="print()" [disabled]="!invoice">
      Imprimer
    </button>

    <!-- ✅ Enregistrer PDF : Electron -->
    <button
      class="btn outline"
      *ngIf="electron.isElectron"
      (click)="exportPdf()"
      [disabled]="!invoice"
    >
      Enregistrer PDF
    </button>

    <!-- ✅ Enregistrer PDF : Web (ouvre Print => Enregistrer en PDF) -->
    <button
      class="btn outline"
      *ngIf="!electron.isElectron"
      (click)="savePdfWeb()"
      [disabled]="!invoice"
    >
      Enregistrer PDF
    </button>
  </div>
</div>

<div class="invoice-page" *ngIf="invoice as inv">
  <!-- ======= TOP HEADER (FR | LOGO | AR) ======= -->
  <header class="top-header">
    <div class="company-fr">
      <div class="line1">SOCIETE PRATIQUES ALUMINIUM</div>
      <div>59, Av. de l’Indépendance - Cité Ettadhamen</div>
      <div>2041 ARIANA</div>
    </div>

    <div class="top-logo">
      <img
        *ngIf="logoAvailable"
        src="assets/logospa.png"
        alt="SPA logo"
        (error)="logoAvailable = false"
      />
      <div *ngIf="!logoAvailable" class="logo-fallback">SPA</div>
    </div>

    <div class="company-ar" dir="rtl" lang="ar">
      <div class="line1">شركة تطبيقات الألومنيوم</div>
      <div>59، شارع الاستقلال - حي التضامن</div>
      <div>2041 أريانة</div>
    </div>
  </header>

  <!-- ======= CLIENT CENTER + DATE RIGHT ======= -->
  <section class="client-row">
    <div class="client-center">
      <div class="client-name">{{ inv.client.nom }}</div>

      <div class="client-sub">{{ inv.client.adresse }}</div>

      <div class="client-sub" *ngIf="inv.client.mf">
        CODE T.V.A : {{ inv.client.mf }}
      </div>
    </div>

    <div class="date-right">
      <div class="muted">Tunis, le</div>
      <div class="date-strong">{{ inv.date | date:'dd/MM/yyyy' }}</div>
    </div>
  </section>

  <!-- ======= TITLE ======= -->
  <div class="invoice-title">
    FACTURE N° <span class="mono">{{ inv.numero }}</span>
  </div>

  <div class="order-line">
    Bon de Commande N° <span class="muted">—</span>
  </div>

  <!-- ======= TABLE ======= -->
  <table class="invoice-table">
    <thead>
      <tr>
        <th class="col-ord">ORD</th>
        <th>DESIGNATIONS</th>
        <th class="col-u">U</th>
        <th class="col-q">QUANT</th>
        <th class="col-pu">P.UNIT</th>
        <th class="col-pt">P.TOTAL</th>
      </tr>
    </thead>

    <tbody>
      <tr *ngFor="let line of inv.lignes; let i = index">
        <td class="center">{{ i + 1 }}</td>
        <td>{{ line.designation }}</td>
        <td class="center">{{ line.unite }}</td>
        <td class="center">{{ line.quantite | number:'1.0-3' }}</td>
        <td class="num">{{ line.prixUnitaire | number:'1.3-3' }}</td>
        <td class="num">{{ calc.lineHT(line) | number:'1.3-3' }}</td>
      </tr>
    </tbody>
  </table>

  <!-- ======= TOTALS RIGHT BOX ======= -->
  <div class="totals-area">
    <table class="totals">
      <tbody>
        <tr>
          <td>TOTAL Hors taxes</td>
          <td class="num">{{ totalsFinal.baseHT | number:'1.3-3' }}</td>
        </tr>

        <tr *ngIf="totals.remise > 0">
          <td>Remise</td>
          <td class="num">- {{ totals.remise | number:'1.3-3' }}</td>
        </tr>

        <tr>
          <td>Fodec (1%)</td>
          <td class="num">{{ totalsFinal.fodec | number:'1.3-3' }}</td>
        </tr>

        <tr>
          <td>TOTAL Hors T.V.A</td>
          <td class="num">{{ totalsFinal.horsTVA | number:'1.3-3' }}</td>
        </tr>

        <tr>
          <td>T.V.A (19%)</td>
          <td class="num">{{ totalsFinal.tva | number:'1.3-3' }}</td>
        </tr>

        <tr>
          <td>Timbre</td>
          <td class="num">{{ totalsFinal.timbre | number:'1.3-3' }}</td>
        </tr>

        <tr class="grand">
          <td>TOTAL T.T.C</td>
          <td class="num">{{ totalsFinal.ttc | number:'1.3-3' }}</td>
        </tr>
      </tbody>
    </table>
  </div>

  <!-- ======= TTC IN WORDS ======= -->
  <div class="ttc-words">
    Arrêtée la présente facture à la somme de :
    <strong>{{ totalTtcText }}</strong>
  </div>

  <!-- ======= FOOTER ======= -->
  <footer class="invoice-footer">
    R.C. : B035 145 2004 - M.F. : 89 83 00 W/A/M/000 - RIB : 25079 0000000 213 555 60 zitouna Mutuelle ville<br>
    Tél. : 71 515 491 - Fax : 70 661 034 - E-mail : saadani.karim@planet.tn
  </footer>
</div>

<div class="empty card" *ngIf="!invoice">
  Facture introuvable.
</div>
